def replace_symbols(text):
    if not text:
        return text

    text = re.sub(r'([ZzsSqwa¬°`]+)Q', r'Q\1', text)

    for old, new in PAIRS:
        while old in text:
            text = text.replace(old, new)

    text = re.sub(r'([а•За•Иа•Ба•Ва§В]+)а•На§∞', r'а•На§∞\1', text)
    text = re.sub(r'а§В([а§Ња•За•Иа•Ба•В]+)', r'\1а§В', text)
    text = re.sub(r'([ \n])а§Њ', r'\1а§ґ', text)

    text = text.replace('¬ѓ', 'f')
    text = text.replace('≈Б', 'а§∞а•Нf')

    text = re.sub(r'([f≈ї])([а§Ха§Ца§Ча§Ша§Ща§Ъа§Ыа§Ьа§Эа§Юа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§µа§ґа§Ја§Єа§єа§Ха•На§Ј])', r'\2\1', text)
    text = re.sub(r'([f≈ї])(а•Н)([а§Ха§Ца§Ча§Ша§Ща§Ъа§Ыа§Ьа§Эа§Юа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§µа§ґа§Ја§Єа§єа§Ха•На§Ј])', r'\2\3\1', text)
    text = re.sub(r'([f≈ї])(а•Н)([а§Ха§Ца§Ча§Ша§Ща§Ъа§Ыа§Ьа§Эа§Юа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§µа§ґа§Ја§Єа§єа§Ха•На§Ј])', r'\2\3\1', text)

    text = text.replace('f', 'а§њ')
    text = text.replace('≈ї', 'а§ња§В')

    text = text.replace('¬±', 'Zа§В')
    text = re.sub(r'([а§Ха§Ца§Ча§Ша§Ъа§Ыа§Ьа§Эа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§≥а§µа§ґа§Ја§Єа§єа§Ха•На§Ја§Ьа•На§Ю])([а§Ња§ња•Аа•Ба•Ва•Га•За•Иа•Ла•Ма§Ва§Б]*)([Z])', r'\3\1\2', text)
    text = re.sub(r'([а§Ха§Ца§Ча§Ша§Ъа§Ыа§Ьа§Эа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§≥а§µа§ґа§Ја§Єа§єа§Ха•На§Ја§Ьа•На§Ю])([а•Н])([Z])', r'\3\1\2', text)
    text = text.replace('Z', 'а§∞а•Н')

    return text


def chanakya_to_unicode(text, chunk_size=6000):
    result = []
    for i in range(0, len(text), chunk_size):
        result.append(replace_symbols(text[i:i + chunk_size]))
    return ''.join(result)

# Reverse table
REVERSE_PAIRS = sorted(
    [(u, c) for c, u in PAIRS],
    key=lambda x: len(x[0]),
    reverse=True
)


def unicode_to_chanakya(text):
    if not text:
        return text

    text = re.sub(
        r'а§∞а•Н([а§Ха§Ца§Ча§Ша§Ъа§Ыа§Ьа§Эа§Юа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§≥а§µа§ґа§Ја§Єа§єа§Ха•На§Ја§Ьа•На§Ю])([а§Ња§ња•Аа•Ба•Ва•Га•За•Иа•Ла•Ма§Ва§Б]*)',
        r'\1\2Z',
        text
    )

    text = text.replace("а§ња§В", "≈ї")

    text = re.sub(
        r'([а§Ха§Ца§Ча§Ша§Ща§Ъа§Ыа§Ьа§Эа§Юа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§µа§ґа§Ја§Єа§єа§Ха•На§Ја§Ьа•На§Ю])а§њ',
        r'f\1',
        text
    )

    text = re.sub(
        r'([а•Н])([а§Ха§Ца§Ча§Ша§Ща§Ъа§Ыа§Ьа§Эа§Юа§Яа§†а§°а§°а§Ља§Ґа§Ґа§Ља§£а§§а§•а§¶а§Іа§®а§™а§Ђа§ђа§≠а§Ѓа§ѓа§∞а§≤а§µа§ґа§Ја§Єа§єа§Ха•На§Ја§Ьа•На§Ю])а§њ',
        r'f\1\2',
        text
    )

    text = text.replace("≈ї", "fа§В")
    for uni, ch in REVERSE_PAIRS:
        text = text.replace(uni, ch)

    return text

